'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { buildRequest } = require('../src/request_options');
const { followRedirect } = require('../src/redirect_policy');

test('request construction marks authorization as sensitive', () => {
  const request = buildRequest('https://api.example.test/jobs', 'secret-token');
  assert.equal(request.sensitiveHeaders.includes('authorization'), true);
});

test('a port change is an authority change and strips credentials', () => {
  const request = {
    url: 'https://api.example.test/jobs',
    headers: { authorization: 'Bearer external' },
    sensitiveHeaders: ['authorization'],
  };
  const redirected = followRedirect(request, 'https://api.example.test:8443/jobs');
  assert.equal(redirected.headers.authorization, undefined);
});

test('a scheme downgrade strips credentials without mutating the input', () => {
  const request = buildRequest('https://api.example.test/jobs', 'secret-token');
  const redirected = followRedirect(request, 'http://api.example.test/jobs');
  assert.equal(redirected.headers.authorization, undefined);
  assert.equal(request.headers.authorization, 'Bearer secret-token');
});
